css:
/*【清荷书】作者：易碎蝶*/
/*本美化免费发布，禁止二传二改*/
/*部分代码用到了其他老师分享的，有标注~*/
/*🍃⭕️←这个是可以调整的部分，以及用了【这个符号】*/

/* ====== 全局字体====== */
@import url("https://fontsapi.zeoseven.com/256/main/result.css");

/* ====== 字体大小控制中心 ====== */
/* ====== 字体大小变量 ====== */
:root {
  --main-body-font-size: 16px;  /* 控制整个页面基础字体 */
  --message-body-font-size: 1em; /* 消息正文字体，相对基础字体 */
  --message-line-height: 1.8;/* 消息行高 */
  --reasoning-line-height: 1.8;/* 思维链行高 */
  --floor-counter-size: 16px;             /* 楼层计数器 */
  --mes-id-size: calc(var(--mainFontSize) * 1);/* 消息ID/楼层显示 */
  --character-name-size: 1em;          /* 角色名称 */
  --timestamp-size: 13px;                  /* 时间戳 */
  --counter-size: calc(var(--mainFontSize) * 1);/* 计时器和字符计数器 */
  --reasoning-header-size: calc(var(--mainFontSize) * 0.75);/* 思维链标题 */
  --reasoning-title-size: 16px;            /* 思维链内容 */
  --input-placeholder-size: 0.7em;        /* 输入框占位符 */
  --select-font-size: 11px;               /* 下拉框 */

  /* 可以添加更多自定义变量 */
  --message-font-size: 1em;
  --ui-font-size: 0.9em;
}

body {
    font-family: "Huiwen-mincho";
    font-weight: normal;
    font-size: var(--main-body-font-size);
}

/*———————— 顶栏 ————————*/
#top-bar {
    position: fixed !important;  
    overflow: visible !important;
    background: none !important;
    border: 0 !important;
    box-shadow: none !important;
    pointer-events: none;
    width: 51vw;  /*宽度*/
    height: 87px;  
    top: 0;
    left: 0;
}

#top-bar::before {
    content: "";
    position: fixed;
    background:  url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=") no-repeat center / cover;  

    /*⭕️顶栏核心 */
    top: 0px;
    left: 0px;
    right: 0px;
    bottom: 34px;/*⭕️只有这里需要改*/


    z-index: 5;
    pointer-events: auto;

    transform: none !important;
    animation: none !important;
}



/* ⭕️顶栏装饰层 */
#top-bar::after {
    content: "";
    position: fixed;
    background: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=") no-repeat center / contain;
    width: 270px;
    height: 200px;
    top: -21px;
    right: 30px;
    z-index: 6;
    pointer-events: none;
    transform-origin: top center;
}

/* 清荷书主题适配 */
div#extensionTopBar {
    /* 高度 */
    height: 45px !important;

    /* 宣纸古黄 - 主色调 */
    background-color: rgba(253, 248, 236, 0.95) !important;

    /* 古书纹理（可选） */
    background-image: 
        linear-gradient(to bottom, 
            rgba(253, 248, 236, 0.95), 
            rgba(250, 244, 228, 0.95)),
        url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" width="100" height="100" opacity="0.03"><rect width="100" height="100" fill="%235a4a4a"/></svg>') !important;

    /* 古书边框色 */
    border-bottom: 1px solid rgba(187, 174, 152, 0.6) !important;

    /* 古旧阴影 */
    box-shadow: 
        0 0 0 1px rgba(255, 253, 245, 0.5),
        0 2px 8px rgba(139, 128, 111, 0.15) !important;

    /* 毛玻璃效果增强古旧感 */
    backdrop-filter: blur(8px) saturate(180%) !important;
    -webkit-backdrop-filter: blur(8px) saturate(180%) !important;
}

/* 内部元素适配 */
#extensionTopBarSearchInput {
    background: rgba(255, 255, 247, 0.8) !important;
    border: 1px solid #aaa795 !important;
    color: #5a4a4a !important;
    font-family: "Huiwen-mincho" !important;
}

/* —————面板背景———— */
.drawer-content {
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 面板背景 */
  background-size: cover; 
  background-position: center; 
  background-repeat: no-repeat; 
  background-attachment: fixed; 
}


/* ===== ⭕️楼层箭头、计数器核心 ===== */
.fa-chevron-right:before,
.fa-chevron-left:before,
.fa-arrow-right:before {
  content: "" !important;
  display: none !important; 
}

.fa-chevron-left,
.fa-chevron-right {
  display: inline-block;
  width: 40px;
  height: 30px; 
  min-width: 0;
  opacity: 1 !important; 
  background: center/contain no-repeat;
}

.fa-chevron-left {
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 左 */
  margin-bottom: -50px; 
}
.fa-chevron-right {
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 右 */
  margin-bottom: -100px; 

}

/* ===== 楼层计数器样式 ===== */
.swipes-counter {
  font-size: var(--floor-counter-size);
  font-weight: 540;
  opacity: 0.5 !important;
  color: #a2a198 !important;
  display: flex;
  justify-content: center;
  align-self: center;
  z-index: 3;
  min-width: 0;
  height: 20px;
  padding: 100px 20px 0; /* ①；需要联合②调整 */
  margin: 0 10px;
  margin-bottom: -40px;/*②；需要联合①调整*/
}

/* ==============================================
🦋气泡拼接开始🦋 *==============================================*/

/* 🍃上层装饰层、拼接气泡顶部 */
.mes::before {
  content: "";
  position: absolute;
  top: -450px; /* 【上下】(负值向上) */
  left: -18px; /* 【左右】 */
  width: 1116px; /* 【宽度/大小】 */
  height: 509px; /* 【高度/大小】 */
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); 
  background-size: contain; 
  background-repeat: no-repeat; 
  z-index: -2; 
  pointer-events: none; 
}


/* 🍃 中层气泡*/
.mes {
   z-index: -3;
  max-width: none;/*【🍃宽度】*/
  width: 100%;/*【👁宽度，一般调整第一个就行，没效果再调整这个】*/
  margin: 460px auto 250px;/*【AI和用户的气泡距离⭕️第一个是调整最早的消息与顶部的距离防止顶部超过屏幕】*/
  border-radius: 0px;
  background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') repeat-y; 
  background-size: 100% auto; 
  background-attachment: local; 
  transition: transform 0.2s ease; 
  transform-origin: top center;
  position: relative;
  overflow: visible;
  box-shadow: none !important; 
}


/* 🍃下层装饰层、拼接气泡尾部 */
.mes::after {
  content: "";
  position: absolute;
  bottom: -249px; /* 【上下】(负值向下) */
  right: -53px; /* 下层装饰层【左右】 */
  width: 900px; /* 【宽度/大小】 */
  height: 274.5px; /* 【高度/大小👁会影响最新消息的底部留白，不可调太高，宽度拉不动再调高一点】 */
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); 
  background-size: contain; 
  background-repeat: no-repeat; 
  z-index: -4; 
  pointer-events: none; 
}

/*——————🍃文本边距——————*/

.mes_text,
.mes_reasoning {
    font-weight: 00;
    line-height:var(--message-line-height);
    text-align: left; 
    overflow-wrap: anywhere;

    /* ⭕️文字边距核心*/

    --top-padding:8rem; /* 顶部 */
    --bottom-padding: 0rem; /* 底部 */
    --left-padding: 1rem; /* 左边距 */
    --right-padding: 1.7rem; /* 右边距 */

/*👁没啥用但不能删↓*/
    padding-top: var(--top-padding);
    padding-bottom: var(--bottom-padding);
    padding-left: var(--left-padding);
    padding-right: var(--right-padding);
    /* 最大宽度控制 */
    max-width: 100%;
    margin: 0; /* 清除默认外边距 */
}

/* ==============================================
🦋气泡拼接结束🍃头像美化开始============================================== */


/*⭕️头像框*/
.mesAvatarWrapper {
  position: absolute;
  top: -147px;
  left: 48.9%;
  transform: translateX(-50%);
  z-index: -1;
  width: 70px;  
  height: 70px; 
  overflow: visible; 
}

/* ⭕️头像框位置与大小调整核心 */
.mesAvatarWrapper::after {
  content: "";
  position: absolute;
  top: 96%;/* 【上下】 */
  left: 180%;/* 【左右】 */
  width: 437%;  /* 【框宽度】 */
  height: 276%; /* 【框高度】 */
  display: block;

  /* ⭕️头像框链接放置处 */
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');/*←🍃*/
  background-size: 100% 100%;
  background-repeat: no-repeat;
  background-position: center;
  transform: translate(-50%, -50%);
  z-index: 1; 

}

.mesAvatarWrapper img {
  position: relative;
  z-index: -1; 
}

/* ⭕️头像位置 */
.mesAvatarWrapper {
  position: absolute;
  top: -359px;           /* 【负值向上】 */
  left: 63.5%;            /* 【头像左右】 */
  transform: translateX(-50%);
  z-index: -1;
}

/* ⭕️头像尺寸*/
.mesAvatarWrapper .avatar {
  /* 🍃头像尺寸 */
  width: 277.5px;           /* 宽度 */
  height: 124px;          /* 高度 */
  transform: rotate(0deg); /* 旋转 */
}
.mesAvatarWrapper .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* ⭕user设置页面/角色选择头像美化⭕*/
.avatar img {
    border: 2px solid white; /* 头像描边 */
    box-shadow: 
        inset -2px -2px 4px rgba(130, 101, 141, 0), 
        4px 4px 3px rgba(107, 102, 66, 0.1);
}
.avatar-container {
    position: relative; 
    border-radius: 0px;
    background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/cover, #fffff7; 
    outline: 1px solid #aaa795; 
    border: 1px solid #fffff7; 
    box-shadow: 
        2px 2px 0px rgba(107, 102, 66, 0.2); 
}

.avatar-container::after {
    content: '';
    position: absolute;
    top: 0;
    right: 0;
    width: 54px; 
    height: 54px; 
    background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/cover no-repeat; 
    transform: translate(30%, -30%); 
}

.bogus_folder_select, 
.character_select {
    position: relative;
    border-radius: 0px;
    margin-bottom: 0px;
    background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/cover, #fffff7; 
    outline: 1px solid #aaa795; 
    border: 1px solid #fffff7;  
    color: #a2a198; /* 文字颜色 */
    box-shadow: 
        3px 3px 0px rgba(107, 102, 66, 0.1); 
}

.bogus_folder_select::after,
.character_select::after {
    content: '';
    position: absolute;
    top: 0;
    right: 0;
    width: 40px; 
    height: 40px; 
    background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') center/cover no-repeat; 
    transform: translate(20%, -30%); 
}

/* ==============================================
🦋头像美化结束🍃文字效果美化开始============================================== */

/* === 设置选项=== */
small {
  color: #626153 !important;
  opacity: 0.8;
}
.toggle-description {
    color: #a2a198;
}
#completion_prompt_manager .completion_prompt_manager_header div {
    color: #a2a198; /*字符*/
}

.fa-solid::before, .fa-regular::before {
    vertical-align: middle;
    text-align: center;
}

.right_menu_button {
    padding: 1px;
    filter: none;
    color: #a2a198 !important; /* 更新文字颜色 */
}

/* === 预设区文字颜色 === */
/* 选中 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
  color: #4e524b;
}

/* 未选 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name, 
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
  color: #cfcfcd;
}

/* 星号等标识颜色*/
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt .completion_prompt_manager_prompt_name .fa-solid {
    color: #a2a198;
}


/* 代码块 */
code, pre {
  background: #fffff7 !important; 
  color: #a2a198 !important; 
  border: 2px solid #fffff7 !important; 
  box-shadow: 
    inset 3px 3px 4px rgba(107, 102, 66, 0), 
    3px 3px 0px rgba(107, 102, 66, 0.1) !important; 
  border-radius: 0px !important; 
}

/* 引用气泡 */
.mes_text q {
  background: linear-gradient(90deg, #ffffff 0%, rgba(255, 255, 255, 1) 100%) !important; 
box-shadow: 
    inset 3px 3px 4px rgba(107, 102, 66, 0), 
    2px 2px 0px rgba(107, 102, 66, 0.1) !important; 
  border-radius: 0 !important;
  font-style: italic;
  font-weight: 300;
}

/* 引用区块 */
.mes_text blockquote, 
.mes_reasoning blockquote {
  border-left: 3px solid #d8d5c5 !important; 
  background: #fffff7 !important; 
  color: #a2a198 !important; 
  box-shadow: 4px 4px 8px rgba(107, 102, 66, 0.1) !important; 
  border-radius: 0 !important;
  font-style: italic;
}

/* 斜体 */
em, i {
  background: linear-gradient(to bottom, 
    rgba(255, 255, 247, 0) 50%, 
    rgba(107, 102, 66, 0.02) 50%) !important; 
  font-style: italic !important; 
}
/* ==============================================
🦋文字效果美化结束🍃零碎美化开始============================================== */

/*—— 🍃楼层 ——*/


.mes .mesIDDisplay {
    position: fixed;
    top: 287.5px;
    left: -237px;                    /* 从左侧开始定位 */
  transform: none;            /* 移除所有变换效果 */
    z-index: 2;
    margin-top: 0px;
    text-align: left;           /* 文字左对齐 */
    width: auto;                /* 宽度自适应内容 */
    white-space: nowrap;        /* 防止文字换行 */
    padding: 0 10px;            /* 添加左右内边距 */
    display: inline-flex; 
    align-items: center;  
    gap: 2px;            /* 【左右文字间距】 */

    cursor: default;
    opacity: 1;
    font-size: var(--mes-id-size);
    font-weight: 300;
    color: #a2a198;      /* 【颜料🎨】【主文字颜色】 */
transform: rotate(0deg); /* 旋转 */
}


/* 左侧文字 */
.mes .mesIDDisplay::before {
    content: var(--left-text, "捻花"); /* 【左侧文字内容】 */
    white-space: nowrap;  
    color: var(--left-color, #a2a198); /* 【颜料🎨】【左侧文字颜色】 */
    font-weight: 300;
}

/* 右侧文字 */
.mes .mesIDDisplay::after {
    content: var(--right-text, ""); /* 【右侧文字内容】 */
    white-space: nowrap;  
    color: var(--right-color, #FFC67F); /* 【颜料🎨】【右侧文字颜色】 */
    font-weight: 300;
}


/*—— 🍃基础信息【时间戳、角色昵称等】 ——*/

/* ⭕️消息文字上边距留白核心调整 */
.mes_block {
  position: relative;
  margin-top: -120px;  
  overflow: visible;
}

/* ⭕️角色名称核心调整 */
.mes_block .ch_name {
  position: relative;
  top: -307px; /* 上下 */
  left: 605px;
  max-width: calc(100% - 105px); 
  min-height: 0px;
  z-index: 10; 
 font-size: var(--character-name-size);
  font-weight: 300;
  letter-spacing: 0.9px;
white-space: nowrap;
    transform: skewX(15deg);
}


/* 角色昵称颜色 */
.mes_block .ch_name {
  color: #a2a198 !important; 
  text-shadow: none !important;
  -webkit-text-stroke: 0 !important; 
}

/* 时间戳颜色 */
.timestamp {
  color: #a2a198 !important; 
  opacity: 1 !important; 
}


/* ⭕️时间戳核心调整 */
.timestamp {
  position: absolute;
  top: 228px;                /* 上下 */
  left: -580px;                /* 左右 */
  width: 300%; 
  font-size: var(--timestamp-size);            /* 字体大小 */
  font-weight: 500;          /* 字体粗细 */
  transform: rotate(0deg);   /* 旋转 */
  white-space: nowrap;
transform: skewX(-15deg);
    display: inline-block;
}

/* 左侧文字 */
.timestamp::before {
  content: "";       /*左侧文字 */
  color: #967aa1;            /* 左侧文字颜色 */
  display: inline;
  padding-right: 0px;        /* 右侧间距（分隔时间戳） */
  pointer-events: none;
}

/* 右侧文字 */
.timestamp::after {
  content: "";       /* 右侧文字 */
  color: #967aa1;            /* 右侧文字颜色 */
  display: inline;
  padding-left: 0px;         /* 左侧间距（分隔时间戳） */
  pointer-events: none;
}


/* ⭕️编辑按钮核心调整 */
.mes_buttons {
  position: absolute;
  top: 270px; /*上下*/
  left: 40px;/*左右*/
  z-index: 30;
  padding: 20px; 
  min-height: 36px;
  overflow: visible !important;
  box-sizing: border-box;
  transform: rotate(0deg); /* 旋转 */
  transform: skewX(-15deg);
  display: flex !important; /* 确保显示 */
  gap: 15px;
}

.mes_edit_buttons {
    display: none;
    flex-direction: row;
    column-gap: 5px;
    float: right;
    cursor: pointer;
    padding-bottom: 8px;
    filter: none; /*移除阴影*/
    transition: 0.3s ease-in-out;

    /* ⭕编辑菜单位置核心调整⭕ */
    position: absolute;
    top: 300px;  /* 负数上移 | 正数下移  */
    left: -565px;
    right: auto;   /* 负数右移 | 正数左移  */
    z-index: 10000;
  transform: rotate(0deg); /* 旋转 */
transform: skewX(-15deg);
}
.mes_edit_down.menu_button.fa-solid.fa-chevron-down.interactable.disabled {
    filter: none !important;
}
.mes_button, .extraMesButtons>div {
cursor: pointer;
    transition: opacity 0.2s ease-in-out;
    filter: drop-shadow(0px 0px 0px #ffffff) !important;
    /* ⭕设置省略号菜单颜色 */
    color: #a2a198 !important;
opacity: 0.4 !important; 
}


/*—— 计时器&字符——*/
.mes {
  position: relative; 
}

.mes .mes_timer,
.mes .tokenCounterDisplay {
  position: fixed; 
  z-index: 3; 
  cursor: default;
opacity: 1;/*透明度*/
  white-space: nowrap; 
  font-size: var(--counter-size);/*文字大小*/
  font-weight: 400;/*文字粗细*/
  padding: 0;
  top: var(--element-top, 240px);
  left: var(--element-left, 50%);
  transform: translateX(var(--element-translate, -50%));
}



/* === ⭕️计时器核心 === */
.mes .mes_timer {
  --element-top: var(--timer-top,294.5px); /*【🍃计时器上下】*/
  --timer-left: -337px; /* 🍃计时器左右 */
--timer-translate: 0; 
  text-align: left; 
  left: var(--timer-left);
  transform: translate(var(--timer-translate), -50%);

  /* 文字内容控制 */
  --timer-prefix: "浮世"; /* 【🍃前缀】 */
