  --counter-main-color: #a2a198; /* 【🍃计数器颜色】 */
    --counter-prefix-color: #a2a198; /* 【🍃前缀颜色】 */
  --counter-suffix-color: #C5D5DF; /* 【🍃后缀颜色】 */
  color: var(--counter-main-color);

