/* 悬停 */
input[type='checkbox']:hover {
  background: 
    linear-gradient(to right, #fffff7, rgba(255, 245, 225, 0.4)),
    url('https://example.com/background.jpg') center/cover;
  border-color: #aaa795; 
  box-shadow: 
    0 0 0 2px #fffff7,
    4px 4px 6px rgba(107, 102, 66, 0.25); 
}

/* 选中 */
input[type='checkbox']:checked {
  background: 
    linear-gradient(to right, #fffff7, rgba(255, 245, 225, 1)),
    url('https://example.com/background.jpg') center/cover;
  border-color: #aaa795; 
  box-shadow: 
    0 0 0 1px #fffff7,
    2px 2px 4px rgba(107, 102, 66, 0.3); 
