/* 选中图标 */
input[type='checkbox']:checked::after {
  content: '-';        
  font-size: 1.7em;/*⭕️调整大小*/
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  color: #c1c0b2;     
  text-shadow: 0 0 4px rgba(255, 255, 255, 0.7); 
}
/* 👁不可删👁勾选隐藏 */
input[type="checkbox"]::before {
  content: none !important;
}



